import{_ as n,C as o,o as d,c as h,j as e,a as i,E as l,a3 as p}from"./chunks/framework.gsMzR_Kb.js";const x=JSON.parse('{"title":"阴符经","description":"一部篇幅极短、语言峻利的道家经典。","frontmatter":{"title":"阴符经","description":"一部篇幅极短、语言峻利的道家经典。","category":"guide","aliases":["阴符经","黄帝阴符经","yinfu jing","阴符"],"source":["《黄帝阴符经》"]},"headers":[],"relativePath":"daoism/starter-texts/yinfu-jing.md","filePath":"daoism/starter-texts/yinfu-jing.md","lastUpdated":1777132262000}'),s={name:"daoism/starter-texts/yinfu-jing.md"};function c(u,a,b,f,m,k){const t=o("DaoReadingPrelude"),r=o("DaoOriginalReading");return d(),h("div",null,[a[0]||(a[0]=e("h1",{id:"阴符经",tabindex:"-1"},[i("阴符经 "),e("a",{class:"header-anchor",href:"#阴符经","aria-label":'Permalink to "阴符经"'},"​")],-1)),l(t,{title:"先分上中下三篇，再顺着机的脉络读",summary:"《阴符经》篇幅不长，但语势峻厉、转折密集。更适合的进入方式，是先按上、中、下三篇分别去读：上篇看天道与杀机，中篇看三盗与时机，下篇看自然之道与阴阳变化。",points:[{label:"先读",text:"先顺着三篇各读一遍，不急着逐句解释。"},{label:"再辨",text:"留意“机”怎样在天、人、万物之间反复出现。"},{label:"后想",text:"最后回到自然之道、应机而动这条总线。"}],hint:"这篇适合分篇读，不必一口气把三篇压成一团；先让每一篇各自立住，再回头看它们如何互相照应。"}),a[1]||(a[1]=e("h2",{id:"【原典层】原文",tabindex:"-1"},[i("【原典层】原文 "),e("a",{class:"header-anchor",href:"#【原典层】原文","aria-label":'Permalink to "【原典层】原文"'},"​")],-1)),a[2]||(a[2]=e("h3",{id:"上篇",tabindex:"-1"},[i("上篇 "),e("a",{class:"header-anchor",href:"#上篇","aria-label":'Permalink to "上篇"'},"​")],-1)),l(r,{chapterMark:"上篇",colophon:"观天 · 杀机 · 修炼",tone:"ink",skin:"yinfu",paragraphs:["观天之道，执天之行，尽矣。","天有五贼，见之者昌。五贼在心，施行于天。宇宙在乎手，万化生乎身。","天性，人也；人心，机也。立天之道，以定人也。","天发杀机，移星易宿；地发杀机，龙蛇起陆；人发杀机，天地反覆。天人合发，万变定基。","性有巧拙，可以伏藏。九窍之邪，在乎三要，可以动静。","火生于木，祸发必克；奸生于国，时动必溃。知之修炼，谓之圣人。"],"aria-label":"阴符经上篇原文"}),a[3]||(a[3]=e("h3",{id:"中篇",tabindex:"-1"},[i("中篇 "),e("a",{class:"header-anchor",href:"#中篇","aria-label":'Permalink to "中篇"'},"​")],-1)),l(r,{chapterMark:"中篇",colophon:"三盗 · 时机 · 神明",tone:"ink",skin:"yinfu",paragraphs:["天生天杀，道之理也。","天地，万物之盗；万物，人之盗；人，万物之盗。三盗既宜，三才既安。","故曰：食其时，百骸理；动其机，万化安。","人知其神之神，不知不神之所以神。日月有数，大小有定；圣功生焉，神明出焉。","其盗机也，天下莫能见，莫能知。君子得之固躬，小人得之轻命。"],"aria-label":"阴符经中篇原文"}),a[4]||(a[4]=e("h3",{id:"下篇",tabindex:"-1"},[i("下篇 "),e("a",{class:"header-anchor",href:"#下篇","aria-label":'Permalink to "下篇"'},"​")],-1)),l(r,{chapterMark:"下篇",colophon:"自然 · 阴阳 · 制机",tone:"ink",skin:"yinfu",paragraphs:["瞽者善听，聋者善视。绝利一源，用师十倍。三返昼夜，用师万倍。","心生于物，死于物，机在目。天之无恩而大恩生，迅雷烈风，莫不蠢然。至乐性余，至静性廉。天之至私，用之至公。禽之制在气。","生者死之根，死者生之根。恩生于害，害生于恩。","愚人以天地文理圣，我以时物文理哲。人以愚虞圣，我以不愚虞圣；人以奇期圣，我以不奇期圣。故曰：沉水入火，自取灭亡。","自然之道静，故天地万物生。天地之道浸，故阴阳胜。阴阳相推，而变化顺矣。","是故圣人知自然之道不可违，因而制之。至静之道，律历所不能契。爰有奇器，是生万象，八卦甲子，神机鬼藏。阴阳相胜之术，昭昭乎进乎象矣。"],"aria-label":"阴符经下篇原文"}),a[5]||(a[5]=p('<h2 id="【原典层】注音-生僻字" tabindex="-1">【原典层】注音 / 生僻字 <a class="header-anchor" href="#【原典层】注音-生僻字" aria-label="Permalink to &quot;【原典层】注音 / 生僻字&quot;">​</a></h2><ul><li>瞽：<code>gǔ</code></li><li>骸：<code>hái</code></li><li>躬：<code>gōng</code></li><li>虞：<code>yú</code></li><li>浸：<code>jìn</code></li><li>爰：<code>yuán</code></li></ul><h2 id="【原典层】分段" tabindex="-1">【原典层】分段 <a class="header-anchor" href="#【原典层】分段" aria-label="Permalink to &quot;【原典层】分段&quot;">​</a></h2><ol><li>上篇：天道、人心、杀机与修炼</li><li>中篇：三盗之理、时机之用、神机难见</li><li>下篇：反常之言、自然之道、阴阳变化</li></ol><h2 id="【原典层】关键词" tabindex="-1">【原典层】关键词 <a class="header-anchor" href="#【原典层】关键词" aria-label="Permalink to &quot;【原典层】关键词&quot;">​</a></h2><ul><li>天道：天地运行之理，不以人的好恶为转移</li><li>机：关键处、发动处、转变处，也是事物变化的枢纽</li><li>杀机：并非单指杀戮，而是变化、转折、肃杀之机</li><li>三盗：天地、万物、人与彼此互取互用的关系</li><li>自然：自然而然，本来如此的运行之道</li><li>阴阳：推移、制衡、变化的基本关系</li><li>修炼：不是玄谈，而是知机、守机、用机的工夫</li></ul><h2 id="【解读层】三问解读" tabindex="-1">【解读层】三问解读 <a class="header-anchor" href="#【解读层】三问解读" aria-label="Permalink to &quot;【解读层】三问解读&quot;">​</a></h2><blockquote><p>解读仅个人观点，仅供参考，若有疏漏还望海涵，并批评指出</p></blockquote><h3 id="象-这部经在说什么" tabindex="-1">象：这部经在说什么 <a class="header-anchor" href="#象-这部经在说什么" aria-label="Permalink to &quot;象：这部经在说什么&quot;">​</a></h3><p>《阴符经》很短，但语气比《清静经》更峻，也更像一把直接切进事物根处的刀。它关心的不是单纯的安静，而是天地万物如何发动、如何变化、如何互相取用，以及人该怎样看见其中的“机”。</p><p>如果说《清静经》更像从“大道”一路落到“清静工夫”，那么《阴符经》更像在提醒人：天地之间没有死物，一切都在动，一切都有机，一切都在转。</p><h3 id="理-为什么这部经重要" tabindex="-1">理：为什么这部经重要 <a class="header-anchor" href="#理-为什么这部经重要" aria-label="Permalink to &quot;理：为什么这部经重要&quot;">​</a></h3><p>这部经重要，正在于它不温吞。</p><ul><li>它逼人正视变化，而不是沉迷于静态理解</li><li>它逼人正视“机”的存在，而不是只看表面现象</li><li>它逼人承认天地运行自有其理，不会因为人的愿望而改变</li><li>它也提醒人：真正的学习，不只是知道概念，而是学会在变化中见机、守机、应机</li></ul><p>因此，它虽然篇幅极短，却很适合作为理解“道并不只是柔和，也有峻厉一面”的入口。</p><h3 id="用-今天怎么进入这部经" tabindex="-1">用：今天怎么进入这部经 <a class="header-anchor" href="#用-今天怎么进入这部经" aria-label="Permalink to &quot;用：今天怎么进入这部经&quot;">​</a></h3><p>今天读《阴符经》，不必急着把每一句都解释得很满。更好的进入方式，也许是先抓住三个问题：</p><ul><li>我平常看到的是表面，还是能慢慢看见事情发动的“机”？</li><li>我有没有把“自然之道”误解成什么都不做？</li><li>面对变化时，我是在被动卷走，还是能稍微看见它、顺应它、调整自己？</li></ul><p>先抓住这几个问题，再回头读原文，往往会更有力。</p><h2 id="【解读层】分段解读" tabindex="-1">【解读层】分段解读 <a class="header-anchor" href="#【解读层】分段解读" aria-label="Permalink to &quot;【解读层】分段解读&quot;">​</a></h2><h3 id="_1-上篇-天道、人心与发动之机" tabindex="-1">1. 上篇：天道、人心与发动之机 <a class="header-anchor" href="#_1-上篇-天道、人心与发动之机" aria-label="Permalink to &quot;1. 上篇：天道、人心与发动之机&quot;">​</a></h3><p>开篇“观天之道，执天之行，尽矣”很有力量。它先不让人困在繁复名相里，而是直指两件事：看见天道，抓住运行。这里的重点不在偏重“观”还是“执”，而在于先观后执、观执相成。若只有观，容易停在“知道”；若只有执，又容易落成盲动。到了“尽矣”，更像是在说：道理与工夫，至少在这一截已经贯通了。</p><p>“天有五贼，见之者昌。五贼在心，施行于天”也很值得连着读。若只看前一句，容易误解成向外争势；但经文紧接着说“五贼在心”，一下又把人从外争拉回内观。关键不只在看见天地运行中那些会夺势、转势的力量，也在看见人心之中本就有相应之机。</p><p>“天性，人也；人心，机也。立天之道，以定人也”则把重点进一步收到“定”字。前面讲天、讲人、讲心、讲机，关系很多，气机也很活，但一个“定”字下来，整句忽然收住了。它不是宿命地说“人由天定”，而更像是在提醒：正因为人心会动、会偏、会被机牵着走，所以才更需要立住一个更高的准绳，使人不乱、不偏、不失其度。</p><p>到了“天发杀机，移星易宿；地发杀机，龙蛇起陆；人发杀机，天地反覆”，上篇的气势突然推高。“杀机”若只按杀戮来读，会太窄；放回这里，它更像是一种剧烈转变的发动点。真正震人的，尤其是“人发杀机，天地反覆”，因为这提醒人：可怕的不是力量本身，而是不定的力量。一旦人心之机发错，后果可能被极大放大。</p><p>但经文并未停在“可怕”上，而是紧接着说“天人合发，万变定基”。变化并没有消失，关键在于天人与其机能否相合。能合，则万变不只是乱变，最后还会沉到一个新的根基上。</p><p>“性有巧拙，可以伏藏。九窍之邪，在乎三要，可以动静”则又把视线从天地大势收回到人的工夫上。这里的“巧拙”不一定只是高下之分，更像是在承认：人的性分本来就不同，有敏捷处，也有迟钝处。但无论巧拙，都不必急着尽发，所以经文紧接着说“可以伏藏”。</p><p>“九窍之邪”也不必先读成抽象的恶，更像是在说：感官一动，心就容易被牵，人的许多散乱与偏移，确实常常借着这些“窍”而起。关键不在于感官永远不动，而在于能否守住那几个真正重要的关节点，使自己仍有“可以动静”的余地。</p><p>到了“火生于木，祸发必克；奸生于国，时动必溃”，上篇又一次提醒人：祸乱并非凭空而来，它总有生处，也总会在某个时候发动。真正要紧的，不只是看见事情爆发后的样子，而是平时就能看见它从哪里生。</p><p>最后一句“知之修炼，谓之圣人”，则把整段的落点收得很严。这里的“圣”不是空名，也不是后来的称号，而是能从细微处看见端倪，又把所见之理拿来修自己、炼自己的人。若只知而不修，不够；若只修而不知，也不够。知与修，在这里本就是一体的工夫。</p><h3 id="_2-中篇-三盗之理与时机" tabindex="-1">2. 中篇：三盗之理与时机 <a class="header-anchor" href="#_2-中篇-三盗之理与时机" aria-label="Permalink to &quot;2. 中篇：三盗之理与时机&quot;">​</a></h3><p>“天地，万物之盗；万物，人之盗；人，万物之盗”读起来很刺耳，却也因此令人停住。它不是鼓励巧取豪夺，而是在指出：天地之间本就是互相资取、互相成就、互相消耗的关系。</p><p>所以关键不在于有没有“取”，而在于是否得其宜、合其时。经文说“三盗既宜，三才既安”，真正重要的是分寸与时机。</p><h3 id="_3-下篇-反常之言与自然之道" tabindex="-1">3. 下篇：反常之言与自然之道 <a class="header-anchor" href="#_3-下篇-反常之言与自然之道" aria-label="Permalink to &quot;3. 下篇：反常之言与自然之道&quot;">​</a></h3><p>下篇最容易让人一口气读过去，又最值得慢下来。它大量使用反转、对照和近乎悖论式的话语，像是在故意打碎人平常顺手的理解。</p><p>到“自然之道静，故天地万物生。天地之道浸，故阴阳胜。阴阳相推，而变化顺矣”，全篇又忽然落回一个更根本的地方：再繁复的变化，终究没有离开自然之道。</p><h2 id="【解读层】现代重述" tabindex="-1">【解读层】现代重述 <a class="header-anchor" href="#【解读层】现代重述" aria-label="Permalink to &quot;【解读层】现代重述&quot;">​</a></h2><p>天地有其自身的运行之理，万物的变化都有发动之机。人若只看表象，常常会错过真正关键的转折点；若能慢慢学着见机、守机、应机，便不会总在变化来临之后才仓促应对。</p><p>《阴符经》提醒人：自然之道并不只是柔和安稳，它也包含肃杀、翻转、制衡与再生。理解这一点，人才不会把“道”误解成空泛的安慰，而会更认真地面对变化本身。</p><h2 id="【解读层】我的理解" tabindex="-1">【解读层】我的理解 <a class="header-anchor" href="#【解读层】我的理解" aria-label="Permalink to &quot;【解读层】我的理解&quot;">​</a></h2><p>对我来说，《阴符经》和《清静经》的气质很不一样。</p><p>《清静经》像是在慢慢把人按回心里，让人看见自己为什么会乱、为什么会被牵走；《阴符经》却更像迎面而来的一阵硬风。它不太安慰人，甚至有些句子一上来就会让人不舒服，比如“天地，万物之盗；万物，人之盗；人，万物之盗”。可也正因为这样，它逼着人承认：天地之间本来就不是一张静止温柔的图画，而是流转、取予、消长、推移。</p><p>我现在初读它，最在意的还不是把每一句都讲透，而是它不断提醒我的那个字：机。很多时候，人不是败在事情太难，而是败在根本没看见它什么时候已经开始变了。等到表面上全都显出来，往往已经迟了。</p><p>读到“立天之道，以定人也”时，我最有感觉的是“定”字。前面又是天、又是人、又是心、又是机，很容易越读越散，可一个“定”字下来，整段忽然收了回来。对我来说，这个“定”不是被动地“由天而定”，而更像是人在更大的秩序之下，把自己安住好。事情依然很多，甚至会同时推进，但一旦根稳了，优先级和次第会慢慢自己显出来，这样的人不是没事做了，而是不再被杂事一路拖着乱跑。</p><p>读到“人发杀机，天地反覆”时，我又会被震一下。前面的“移星易宿”“龙蛇起陆”还是天地自然的宏伟之变，可一到“天地反覆”，就会忽然感到人的力量之大。人若不定，力量就会很可怕，甚至会反过来伤到自己。</p><p>再往后读“性有巧拙，可以伏藏。九窍之邪，在乎三要，可以动静”，我更有感觉的反而不是“巧拙”，而是“伏藏”与“动静”。感官会动，欲望会起，就像风来时枝叶摆动，这是自然之理。关键不在于枝叶一点都不能动，而在于根是否还在，干是否还立得住。对我来说，根像是记得自己当下在做什么，干像是主体还在，没有被一阵风整棵吹倒。若根在、干在，即使一时被带动，也不必太懊恼，因为动过之后，仍然可以回来。</p><p>再读“火生于木，祸发必克；奸生于国，时动必溃”，我会想到《易》里的“履霜坚冰至”。很多事情不是到了结果才忽然发生的，而是在很早之前就已经有了生处，有了端倪。若能在“火生于木”时就看见后面的祸，在“奸生于国”时就看见后面的溃，那才是真的知微。</p><p>所以“知之修炼，谓之圣人”这句，我现在更愿意读成：所谓“圣”，未必先是地位，也未必先是后人的封号，而是知微而自修。能看见细微处的势，又能把这个看见反过来修自己，不停在“我懂了”，而是一直做到身上，这样的人才慢慢有了“圣”的意味。</p><p>对现在的我来说，“知”和“修”也越来越不像两件事。就像一边讨论、一边整理、一边完善 Dao，其实也已经是一边在修 Dao、一边在被 Dao 反过来修。若把它们硬分开，反而会失掉它原本活的地方。</p><p>所以这篇我更想慢慢读。它不像《清静经》那样，先给人一个可以安顿下来的地方；它更像先把人叫醒，再问一句：你真的看见了吗？</p><h2 id="参考来源" tabindex="-1">参考来源 <a class="header-anchor" href="#参考来源" aria-label="Permalink to &quot;参考来源&quot;">​</a></h2><ul><li>《黄帝阴符经》</li><li><a href="https://zh.wikisource.org/wiki/%E9%BB%83%E5%B8%9D%E9%99%B0%E7%AC%A6%E7%B6%93" target="_blank" rel="noreferrer">维基文库：黃帝陰符經</a></li></ul>',52))])}const P=n(s,[["render",c]]);export{x as __pageData,P as default};
